class McElieceParams:
    @staticmethod
    def public_key_bytes(n: int, k: int) -> int:
        r = n - k
        return (k * r + 7) // 8

    @staticmethod
    def ciphertext_bytes(m: int, t: int) -> int:
        r = m * t
        return (r + 7) // 8

    @staticmethod
    def compare_category(cat1_params: dict, cat5_params: dict) -> dict:
        pk1 = McElieceParams.public_key_bytes(cat1_params['n'], cat1_params['k'])
        pk5 = McElieceParams.public_key_bytes(cat5_params['n'], cat5_params['k'])
        return {
            'pk_ratio': pk5 / pk1,
            'cat1_pk_kb': pk1 / 1024,
            'cat5_pk_kb': pk5 / 1024
        }

import hashlib

def decaps_with_implicit_rejection(
    decode_result: bytes,
    expected_weight: int,
    secret_seed: bytes,
    ciphertext: bytes
) -> bytes:
    if decode_result is not None:
        # Check weight
        weight = sum(bin(b).count('1') for b in decode_result)
        if weight == expected_weight:
            return hashlib.sha3_256(b'success' + decode_result).digest()

    # Implicit rejection: deterministic but unpredictable
    return hashlib.sha3_256(b'reject' + secret_seed + ciphertext).digest()

import numpy as np
from typing import Optional

def to_systematic(H: np.ndarray) -> Optional[np.ndarray]:
    r, n = H.shape
    k = n - r
    H_work = H.copy() % 2

    for col in range(k, n):
        rel = col - k
        # Find pivot
        pivot = None
        for row in range(rel, r):
            if H_work[row, col] == 1:
                pivot = row
                break

        if pivot is None:
            # Try column swap
            for sc in range(col):
                if H_work[rel, sc] == 1:
                    H_work[:, [col, sc]] = H_work[:, [sc, col]]
                    break
            pivot = rel

        H_work[[rel, pivot]] = H_work[[pivot, rel]]

        for row in range(r):
            if row != rel and H_work[row, col] == 1:
                H_work[row] = (H_work[row] + H_work[rel]) % 2

    return H_work

def recommend_scheme(
    max_pk_kb: float,
    security_confidence: str,
    bandwidth_critical: bool
) -> str:
    if security_confidence == 'maximum' and max_pk_kb >= 255:
        return 'Classic McEliece (maximum security confidence)'
    elif max_pk_kb < 10 or bandwidth_critical:
        return 'ML-KEM (compact keys and ciphertexts)'
    elif security_confidence == 'maximum':
        return 'Hybrid ML-KEM + Classic McEliece (if bandwidth allows)'
    else:
        return 'ML-KEM (good balance of security and efficiency)'
